INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_conducao_embriaguez' LIMIT 1), 'Durante fiscalização de trânsito em Campina Grande, agente da STTP constata que o condutor apresenta sinais evidentes de alteração da capacidade psicomotora. O condutor recusa-se a submeter-se ao teste do etilômetro. Considerando o CTB, assinale a alternativa CORRETA:', 'A recusa impede a autuação, pois o teste depende de consentimento livre do condutor.', 'O agente deve aguardar perito criminal antes de lavrar qualquer auto de infração.', 'A recusa em se submeter ao teste constitui infração autônoma prevista no CTB.', 'A infração somente se configura se o etilômetro confirmar concentração acima do limite legal.', NULL, 'C', 'caso_pratico', 'pegadinha_pode_deve', 4, '{"o_que_testa":"Conhecimento sobre embriaguez ao volante e consequência jurídica da recusa ao etilômetro.","fundamento_legal":"CTB, art. 165-A: recusar-se a ser submetido a teste, exame clínico, perícia ou outro procedimento que permita certificar influência de álcool ou outra substância psicoativa, na forma do art. 277, configura infração autônoma de trânsito.","passo_a_passo":["O enunciado descreve sinais de alteração psicomotora + recusa ao etilômetro.","A) Erra: a recusa não impede autuação — é infração autônoma (art. 165-A).","B) Erra: não é necessário aguardar perito para autuação administrativa.","C) Correta: a recusa configura infração autônoma prevista no art. 165-A do CTB.","D) Erra: confunde necessidade de confirmação etílica com a recusa em si."],"pegadinha":"IDECAN troca recusa por necessidade de confirmação etílica — candidato acha que sem teste positivo não há infração.","macete":"Recusou o bafômetro = infração autônoma (art. 165-A). Não precisa estar bêbado no teste.","estudo_reverso":["CTB art. 165","CTB art. 165-A","CTB art. 277"]}'::jsonb, '{"embriaguez","etilometro","recusa"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_snt_competencias' LIMIT 1), 'Em operação de fiscalização em via municipal de Campina Grande, agente da STTP lavra auto de infração por estacionamento irregular. O condutor sustenta que apenas a Polícia Militar pode autuar, pois se trata de poder de polícia ostensivo. Com base no CTB e nas competências do Sistema Nacional de Trânsito, assinale a alternativa CORRETA:', 'A autuação por estacionamento em via municipal é atribuição exclusiva da Polícia Militar, cabendo à STTP apenas orientação ao condutor.', 'O órgão executivo de trânsito do Município pode autuar e aplicar penalidades por infrações de circulação, estacionamento e parada.', 'A STTP somente pode autuar se houver delegação expressa do órgão máximo executivo de trânsito da União para cada agente.', 'Infrações de estacionamento em vias urbanas dependem de autorização prévia do CONTRAN, não podendo o Município autuar diretamente.', NULL, 'B', 'caso_pratico', 'pegadinha_pode_deve', 3, '{"o_que_testa":"Competência do órgão executivo de trânsito municipal (STTP) para fiscalizar e autuar infrações de circulação, estacionamento e parada.","fundamento_legal":"CTB, art. 24, VI: compete aos órgãos e entidades executivos de trânsito dos Municípios executar a fiscalização de trânsito em vias terrestres, autuar e aplicar as penalidades de advertência por escrito e multa e as medidas administrativas cabíveis pelas infrações previstas neste Código.","passo_a_passo":["O caso envolve autuação municipal por estacionamento — hipótese típica de competência local.","A) Erra: a PM tem policiamento ostensivo (art. 23), mas não exclusividade para autuar estacionamento urbano.","B) Correta: o art. 24, VI confere ao órgão municipal executar fiscalização e autuar infrações de circulação, estacionamento e parada.","C) Erra: não exige delegação individual por agente; a competência é do órgão municipal.","D) Erra: inventa exigência de autorização prévia do CONTRAN para cada autuação."],"pegadinha":"IDECAN mistura policiamento ostensivo da PM com competência exclusiva de autuação, ignorando o art. 24 do CTB.","macete":"Município autua circulação, estacionamento e parada (art. 24, VI). PM patrulha e atua no ostensivo (art. 23).","estudo_reverso":["CTB art. 21","CTB art. 23","CTB art. 24","CTB art. 280"]}'::jsonb, '{"snt","competencia","sttp","municipal"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_sinalizacao' LIMIT 1), 'Motorista autuado por desrespeitar placa de regulamentação alega, em defesa, que a sinalização vertical estava apagada e mal posicionada, dificultando a leitura. O órgão de trânsito com circunscrição sobre a via reconhece a insuficiência da sinalização. À luz do CTB, assinale a alternativa INCORRETA:', 'Não serão aplicadas sanções por inobservância à sinalização quando esta for insuficiente ou incorreta.', 'O órgão ou entidade de trânsito com circunscrição sobre a via responde pela falta ou incorreta colocação da sinalização.', 'A insuficiência da sinalização impede a aplicação das sanções previstas no CTB ao condutor autuado.', 'Reconhecida a falha na sinalização, as sanções devem ser aplicadas normalmente, cabendo ao condutor exigir apenas a correção da via.', NULL, 'D', 'caso_pratico', 'incorreta', 2, '{"o_que_testa":"Efeito da sinalização insuficiente ou incorreta sobre a aplicação de sanções e responsabilidade do órgão de trânsito.","fundamento_legal":"CTB, art. 90: não serão aplicadas as sanções previstas neste Código por inobservância à sinalização quando esta for insuficiente ou incorreta. § 1º: o órgão ou entidade de trânsito com circunscrição sobre a via é responsável pela implantação da sinalização.","passo_a_passo":["Comando INCORRETA: busca a afirmativa falsa.","A) Verdadeira — caput do art. 90 (não é gabarito porque pede a incorreta).","B) Verdadeira — art. 90, § 1º.","C) Verdadeira — consequência do caput do art. 90.","D) Falsa — com sinalização insuficiente ou incorreta, as sanções não se aplicam ao condutor."],"pegadinha":"Candidato acha que falha na sinalização só obriga o órgão a consertar a via, mas não afasta a multa.","macete":"Sinalização ruim = sem sanção ao condutor + responsabilidade do órgão da via (art. 90).","estudo_reverso":["CTB art. 90","CTB art. 91","CTB art. 94"]}'::jsonb, '{"sinalizacao","art_90","excecao"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Na Av. Epitácio Pessoa, em Campina Grande, semáforo exibe luz vermelha para o fluxo que segue em frente. Há placa regulamentar autorizando conversão à direita com o sinal vermelho. Condutor reduz a velocidade, verifica pedestres e ciclistas e efetua a conversão à direita. Agente da STTP pretende autuá-lo por avançar o sinal vermelho. Considerando o CTB, assinale a alternativa CORRETA:', 'A conversão à direita é permitida quando houver sinalização indicativa, observados os deveres de prudência do condutor.', 'O avanço do sinal vermelho é infração gravíssima em qualquer hipótese, ainda que exista placa de conversão à direita.', 'A conversão somente é lícita se o semáforo possuir seta verde exclusiva para a direita, independentemente de placa.', 'A placa de conversão autoriza apenas veículos de transporte coletivo, não se estendendo a automóveis de passeio.', NULL, 'A', 'caso_pratico', 'caso_pratico', 4, '{"o_que_testa":"Exceção ao art. 208 mediante conversão à direita com sinalização permissiva (art. 44-A).","fundamento_legal":"CTB, art. 44-A: é livre o movimento de conversão à direita diante de sinal vermelho do semáforo onde houver sinalização indicativa que permita essa conversão, observados os arts. 44, 45 e 70. CTB, art. 208: avançar o sinal vermelho, exceto onde houver sinalização que permita a livre conversão à direita prevista no art. 44-A.","passo_a_passo":["Há placa autorizando conversão à direita no vermelho — hipótese do art. 44-A.","A) Correta: reproduz a regra do art. 44-A com observância dos deveres de prudência.","B) Erra: o art. 208 expressamente excepciona a conversão com sinalização.","C) Erra: não exige seta verde; basta sinalização indicativa.","D) Erra: a norma não restringe a veículos de coletivo."],"pegadinha":"Candidato aplica o art. 208 sem a ressalva do art. 44-A ou exige seta verde inexistente na lei.","macete":"Vermelho + placa de conversão à direita = pode converter (art. 44-A), com prudência (arts. 44 e 45).","estudo_reverso":["CTB art. 44","CTB art. 44-A","CTB art. 208"]}'::jsonb, '{"semaforo","conversao","art_208","art_44-A"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Quanto às infrações por excesso de velocidade previstas no CTB, analise as assertivas:
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Durante blitz educativa da STTP em Campina Grande, agente aborda veículo em movimento e constata que o motorista e o passageiro do banco dianteiro estão sem cinto de segurança. O condutor alega que a fiscalização só pode aplicar multa, sem reter o veículo. Com base no CTB, assinale a alternativa CORRETA:', 'É cabível a retenção do veículo até que o infrator coloque o cinto de segurança.', 'A medida administrativa é a remoção do veículo ao pátio municipal por 24 horas.', 'Somente o condutor pode ser autuado; passageiro sem cinto não gera medida administrativa.', 'A retenção do veículo depende de ordem judicial, pois a infração é de natureza grave.', NULL, 'A', 'caso_pratico', 'pegadinha_pode_deve', 3, '{"o_que_testa":"Medida administrativa aplicável à infração de não uso do cinto de segurança (art. 167).","fundamento_legal":"CTB, art. 167: deixar o condutor ou passageiro de usar o cinto de segurança, conforme previsto no art. 65 — infração grave; penalidade multa; medida administrativa: retenção do veículo até colocação do cinto pelo infrator.","passo_a_passo":["Infração: condutor e passageiro sem cinto — art. 167.","A) Correta: medida administrativa expressa no art. 167 é retenção até colocação do cinto.","B) Erra: remoção ao pátio não é a medida do art. 167.","C) Erra: o art. 167 menciona condutor ou passageiro.","D) Erra: a retenção é medida administrativa prevista em lei, sem ordem judicial."],"pegadinha":"Confundir retenção até regularizar (art. 167) com remoção ao pátio de outros tipos de infração.","macete":"Sem cinto = grave + retenção até colocar o cinto (art. 167).","estudo_reverso":["CTB art. 65","CTB art. 167","CTB art. 168"]}'::jsonb, '{"cinto","art_167","medida_administrativa"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Agente da STTP autua proprietário de veículo estacionado a menos de cinco metros do bordo do alinhamento da via transversal, obstruindo parcialmente a visibilidade do cruzamento. O condutor contesta a classificação da infração. De acordo com o CTB, assinale a alternativa INCORRETA:', 'Configura infração de natureza média, com penalidade de multa.', 'É admitida medida administrativa de remoção do veículo.', 'Trata-se de infração leve, pois o veículo permaneceu estacionado e não em movimento.', 'A hipótese está prevista no art. 181 do CTB, inciso I.', NULL, 'C', 'caso_pratico', 'incorreta', 3, '{"o_que_testa":"Classificação da infração de estacionamento nas esquinas a menos de cinco metros (art. 181, I).","fundamento_legal":"CTB, art. 181, I: estacionar o veículo nas esquinas e a menos de cinco metros do bordo do alinhamento da via transversal — infração média; penalidade multa; medida administrativa remoção do veículo.","passo_a_passo":["Comando INCORRETA: identificar afirmativa falsa sobre estacionamento irregular em esquina.","A) Verdadeira — infração média com multa.","B) Verdadeira — remoção é medida administrativa do inciso I.","C) Falsa — a infração é MÉDIA, não leve.","D) Verdadeira — hipótese do art. 181, I."],"pegadinha":"Associar estacionamento a infração leve por não envolver veículo em movimento — o CTB classifica como média.","macete":"Esquina < 5 m = média + remoção (art. 181, I).","estudo_reverso":["CTB art. 181","CTB art. 182","CTB art. 183"]}'::jsonb, '{"estacionamento","art_181","gravidade"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_processo_administrativo' LIMIT 1), 'Sobre o auto de infração de trânsito, analise as afirmativas:
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_circulacao_conduta' LIMIT 1), 'Agente da STTP flagra condutor que, em via arterial de Campina Grande, utiliza telefone celular encostado ao ouvido enquanto conduz motocicleta em movimento. O condutor argumenta que a infração seria apenas leve por não colocar outros usuários em risco imediato. À luz do CTB, assinale a alternativa CORRETA:', 'A conduta configura infração leve, pois não há menção expressa a apreensão do veículo.', 'A utilização de telefone celular sem dispositivo mãos-livres configura infração média.', 'Somente é infração se o condutor estiver em velocidade superior ao limite da via.', 'A autuação é inválida, pois motociclistas estão dispensados do uso de cinto e de restrições a celular.', NULL, 'B', 'caso_pratico', 'pegadinha_pode_deve', 3, '{"o_que_testa":"Infração por dirigir utilizando telefone celular (art. 252, VI) e sua classificação.","fundamento_legal":"CTB, art. 252, VI: dirigir o veículo utilizando-se de fones nos ouvidos conectados a aparelhagem sonora ou de telefone celular — infração média; penalidade multa.","passo_a_passo":["Condutor usa celular ao ouvido em motocicleta em movimento.","A) Erra: a infração é média, não leve.","B) Correta: art. 252, VI — celular sem mãos-livres = infração média.","C) Erra: não condiciona a infração ao excesso de velocidade.","D) Erra: motociclistas não estão dispensados; o inciso VI não exclui motos."],"pegadinha":"Candidato subestima a gravidade (leve) ou acha que moto está fora do alcance do art. 252.","macete":"Celular na orelha ao volante = média (art. 252, VI).","estudo_reverso":["CTB art. 252","CTB art. 65","CTB art. 167"]}'::jsonb, '{"celular","art_252","conduta"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Em rodovia que corta o município de Campina Grande, condutor transita a 40 km/h em via cuja velocidade máxima regulamentada é de 100 km/h, formando longa fila de veículos e obstruindo o fluxo, sem condições climáticas adversas, estando na faixa da esquerda. Considerando o CTB, assinale a alternativa CORRETA:', 'A conduta configura infração grave por transitar em velocidade inferior à metade da máxima permitida, retardando o trânsito.', 'Não há infração, pois transitar abaixo do limite máximo é sempre permitido ao condutor prudente.', 'Configura infração média, pois o excesso de cautela não obstrui o trânsito quando há acostamento.', 'A autuação compete exclusivamente à Polícia Rodoviária Federal, não à STTP municipal.', NULL, 'A', 'caso_pratico', 'pegadinha_pode_deve', 3, '{"o_que_testa":"Infração por velocidade muito abaixo do limite retardando ou obstruindo o trânsito (art. 219).","fundamento_legal":"CTB, art. 219: transitar com o veículo em velocidade inferior à metade da velocidade máxima estabelecida para a via, retardando ou obstruindo o trânsito, salvo se as condições de tráfego e meteorológicas não o permitirem, exceto se estiver na faixa da direita — infração grave; penalidade multa.","passo_a_passo":["40 km/h em via de 100 km/h = inferior à metade (50 km/h), retardando trânsito, sem clima adverso, na faixa da esquerda.","A) Correta: preenche os elementos do art. 219 (grave).","B) Erra: velocidade excessivamente baixa pode ser infração.","C) Erra: a infração é grave, não média.","D) Erra: em rodovia federal a PRF autua, mas a questão testa a tipificação, não a competência neste distrator."],"pegadinha":"Achar que ''abaixo do limite'' nunca é infração — o art. 219 pune velocidade excessivamente baixa que obstrui o fluxo.","macete":"Menos da metade do limite + obstruir trânsito = grave (art. 219), salvo clima ruim ou faixa da direita.","estudo_reverso":["CTB art. 219","CTB art. 218","CTB art. 220"]}'::jsonb, '{"velocidade","art_219","obstrucao"}'::text[]);
INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_engenharia_fiscalizacao' LIMIT 1), 'Prefeitura de Campina Grande analisa projeto de shopping center em área que, segundo estudo de impacto, concentrará intenso fluxo de veículos. O secretário de planejamento questiona quais requisitos o CTB impõe antes da aprovação do empreendimento. Assinale a alternativa CORRETA:', 'Basta aprovação do projeto pelo município, pois estacionamento é faculdade do empreendedor.', 'Exige-se apenas licença ambiental, sendo dispensável anuência do órgão de trânsito.', 'O projeto deve contar com anuência prévia do órgão de trânsito com circunscrição sobre a via e previsão de área de estacionamento e vias de acesso.', 'A anuência do CONTRAN é obrigatória para qualquer edificação comercial em vias municipais.', NULL, 'C', 'lei_seca', 'lei_seca', 2, '{"o_que_testa":"Requisitos para aprovação de empreendimento que constitua pólo atrativo de trânsito (art. 93).","fundamento_legal":"CTB, art. 93: nenhum projeto de edificação que possa transformar-se em pólo atrativo de trânsito poderá ser aprovado sem prévia anuência do órgão ou entidade com circunscrição sobre a via e sem que do projeto conste área para estacionamento e indicação das vias de acesso adequadas.","passo_a_passo":["Shopping com alto fluxo = potencial pólo atrativo de trânsito.","A) Erra: estacionamento e anuência de trânsito são exigidos pelo art. 93.","B) Erra: licença ambiental não substitui anuência do órgão de trânsito.","C) Correta: reproduz o art. 93.","D) Erra: a anuência é do órgão com circunscrição sobre a via, não do CONTRAN diretamente."],"pegadinha":"Trocar anuência do órgão local de trânsito por anuência do CONTRAN ou dispensar estacionamento no projeto.","macete":"Pólo atrativo = anuência do órgão da via + estacionamento + acessos (art. 93).","estudo_reverso":["CTB art. 91","CTB art. 93","CTB art. 94"]}'::jsonb, '{"engenharia","art_93","empreendimento"}'::text[]);
